import React from 'react'

function ImageSlider(props) {
    return (
        <>
        <div>
            {props.images.map((image,index)=>(
                <div key={index===1}>
                    <img style={{height:'138px',width:'200px'}}src={`http://localhost:5000/${image}`} alt="productImage" />
                </div>
            ))}
        </div>
        </>
    )
}

export default ImageSlider
